request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?kaufElem ?berElem ?kaufName ?berName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0ae2e7d8093840cc8a65c475b6275cae" ;
         tai:belongsTo ?org .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?kaufElem tai:belongsTo ?choreo ;
            bbo:name ?kaufName .
  FILTER(CONTAINS(LCASE(STR(?kaufName)), "kaufwunsch"))

  ?berElem tai:belongsTo ?choreo ;
           bbo:name ?berName .
  FILTER(CONTAINS(LCASE(STR(?berName)), "beratung"))

  ?kaufElem ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?berElem .
}
LIMIT 25
